import{_ as t,c as s,o as n,ae as r}from"./chunks/framework.Cd-3tpCq.js";const a="data:image/png;base64,",o="/assets/ddev-01.CVHx7-kU.png",i="/assets/ddev-phpstorm.CQZVQbeT.png",D=JSON.parse('{"title":"DDEV","description":"","frontmatter":{},"headers":[],"relativePath":"drupal-project/installation/ddev.md","filePath":"drupal-project/installation/ddev.md"}'),l={name:"drupal-project/installation/ddev.md"};function u(d,e,c,p,g,m){return n(),s("div",null,e[0]||(e[0]=[r('<h1 id="ddev" tabindex="-1"><img src="'+a+'" alt="DDEV logo"> DDEV <a class="header-anchor" href="#ddev" aria-label="Permalink to &quot;![DDEV logo](images/ddev.png) DDEV&quot;">​</a></h1><h2 id="qu-est-ce-que-ddev" tabindex="-1">Qu&#39;est-ce que DDEV ? <a class="header-anchor" href="#qu-est-ce-que-ddev" aria-label="Permalink to &quot;Qu&#39;est-ce que DDEV ?&quot;">​</a></h2><p><strong>DDEV</strong> est un outil open source qui permet de créer des environnements de développement locaux en quelques minutes, basé sur Docker. Il est conçu pour simplifier radicalement la mise en place d&#39;un projet web (Drupal, WordPress, Laravel, etc.) sans avoir à configurer manuellement chaque service (serveur web, base de données, PHP, etc.).</p><p>En résumé : <strong>DDEV</strong> fait tout le travail de configuration Docker à votre place.</p><p>Pas besoin de mettre en place manuellement chaque service (serveur web, base de données, PHP, etc.), des fichiers de configuration, des makefiles pour simplifier les workflows, etc.. <strong>DDEV</strong> fait tout.</p><h2 id="prerequis" tabindex="-1">Prérequis <a class="header-anchor" href="#prerequis" aria-label="Permalink to &quot;Prérequis&quot;">​</a></h2><p>Nous avons besoin d&#39;un fournisseur Docker sur notre système avant de pouvoir installer DDEV.</p><p>Pour plus d&#39;informations sur les fournisseurs Docker, en fonction de votre système, consulter la <a href="https://docs.ddev.com/en/stable/users/install/docker-installation/" target="_blank" rel="noreferrer">Documentation DDEV</a>.</p><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><p>La <a href="https://docs.ddev.com/en/stable/users/install/ddev-installation/" target="_blank" rel="noreferrer">Documentation DDEV</a> est très claire sur comment installer <strong>DDEV</strong>.</p><p>Ayant déjà un fournisseur Docker installé sur mon système Windows (Docker Desktop avec la distribution Ubuntu), j&#39;ai suivi les étapes suivantes :</p><ul><li>J&#39;ai téléchargé l&#39;installeur de DDEV pour Windows (architecture AMD64).</li><li>Durant l&#39;installation, j&#39;ai sélectionné <em>Ubuntu</em> comme distribution.</li></ul><p>L&#39;installeur a automatiquement configuré <strong>DDEV</strong> par rapport à mon fournisseur Docker.</p><p>Pour vérifier l&#39;installation, ouvrir une invite de commande dans WSL2 (interpréteur de commandes Linux) et exécuter la commande suivante :</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ddev</span></span></code></pre></div><p>Le terminal doit afficher le dashboard de <strong>DDEV</strong>.</p><p><img src="'+o+'" alt="DDEV dashboard"><em>DDEV dashboard</em></p><div class="tip custom-block"><p class="custom-block-title">💡 Quitter le dashboard</p><p>Pour quitter le dashboard, appuyer sur la touche <code>q</code>.</p></div><h2 id="plugin-phpstorm" tabindex="-1">Plugin PHPStorm <a class="header-anchor" href="#plugin-phpstorm" aria-label="Permalink to &quot;Plugin PHPStorm&quot;">​</a></h2><p>Si vous utilisez <strong>PHPStorm</strong> comme IDE, sachez qu&#39;un plugin est disponible : <strong>DDEV Integration</strong>.</p><p>Ce plugin apporte les fonctionnalités suivantes :</p><ul><li><strong>Complétion</strong> : <em>config.yaml</em> de <strong>DDEV</strong> est automatiquement détecté. De l&#39;autocomplétion et des suggestions sont proposées.</li><li>Intégration dans le <strong>terminal</strong> : Possibilité de se connecter directement dans le container <strong>DDEV</strong> dans le terminal. Cliquez sur la flèche pour sélectionner le type de terminal et choisissez <em>DDEV web container</em>.</li><li>Configuration de la <strong>Base de données</strong> : dès le démarrage de l&#39;IDE, une connexion à la base de données est automatiquement faites avec l&#39;utilisateur <code>db</code>. Cette connexion est visible dans la fenêtre <em>Database</em>.</li></ul><p>Pour l&#39;installer, rendez-vous dans &quot;Settings -&gt; Plugins -&gt; Marketplace&quot; et cherchez <strong>DDEV Integration</strong>.</p><p><img src="'+i+'" alt="Plugin DDEV Integration dans PHPStorm"><em>Plugin DDEV Integration dans PHPStorm</em></p><p>Cliquez ensuite sur &quot;Install&quot;, puis sur &quot;Apply&quot; et &quot;OK&quot; pour fermer la fenêtre. <strong>PHPStorm</strong> devrait détecter automatiquement <strong>DDEV</strong>.</p><div class="info custom-block"><p class="custom-block-title">Pour le moment, nous n&#39;avons aucun projet <strong>DDEV</strong> configuré.</p><p>Nous allons tout de suite y remédier et installer <strong>Drupal</strong> dans <a href="/drupal-project/installation/drupal.html">la prochaine étape</a></p></div>',26)]))}const h=t(l,[["render",u]]);export{D as __pageData,h as default};
